{
  "name": "Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "Up to 200% of the federal poverty level (FPL), 60% of the state median income (SMI), or 80% of the area median income (AMI), whichever is higher. Exact dollar amounts vary by household size, year, and location; contact local agency for current table as no specific figures provided in sources. Households qualifying for LIHEAP automatically qualify.[1][2][3]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Home must pass energy audit for improvements; not all homes qualify for upgrades even if income-eligible.", "Renters need landlord approval.", "Homeownership or rental status accepted (single-family, mobile, duplex, multi-family)."][2][5]
  },
  "benefits": {
    "type": "service",
    "value": "Free comprehensive energy audit by certified professional, followed by cost-effective upgrades to improve efficiency, health, and safety (e.g., insulation, air sealing; not guaranteed specific items like window replacement). Conservation education provided.[1][2][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local weatherization agency by county (full list at https://www.commerce.wa.gov/weatherization/); examples: OIC of Washington (Adams County) 509-452-7145 be.r@oicofwa.org; Community Action Partnership (Asotin) 208-746-3351 wx@cap4action.org; WAGAP/NCAC (Klickitat/Skamania) (800) 755-1192 or https://www.yvfwc.com/service/home-weatherization; Snohomish County 425-388-7205 weatherization@snoco.org.[1][2][5]"],
    "processing_time": "Not specified; varies by local agency.",
    "waitlist": "Likely due to high demand, but not explicitly detailed; regional variation expected.",
    "forms": ["No specific form names/numbers listed; local agencies handle qualification and acceptance."],
    "documents": ["Income verification documents; for renters, landlord agreement/approval. Prepare proof of household income, residency, and home ownership/rental status."][2][5]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via local agencies; must contact agency serving your county.",
    "regional_variations": "Administered by different local agencies per county with varying contact info, providers, and potentially wait times; e.g., WAGAP/NCAC in Klickitat/Skamania vs. Snohomish County program.[1][2][5]",
    "offices_or_providers": ["County-specific agencies listed at https://www.commerce.wa.gov/weatherization/ (e.g., OIC of Washington for Adams, Community Action Partnership for Asotin)."][2]
  },
  "official_source": "https://www.commerce.wa.gov/weatherization/",
  "gotchas": ["Income eligibility does not guarantee home improvements; depends on audit results and cost-effectiveness.", "Not a window replacement or specific upgrade guarantee program.", "State Commerce Dept does not accept applications directly—must go through local agency.", "Renters need landlord approval.", "Eligibility confirmed only by local agency, which may have slightly varying guidelines."[1][2][4][5]],
  "data_shape_notes": "Administered county-by-county through local agencies with centralized eligibility guidelines; benefits determined post-audit, not fixed dollar amounts; automatic qualification if on LIHEAP."
}

{
  "name": "Health Insurance Counseling and Advocacy Program (HICAP/SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, their families, and caregivers, including those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[3][7]",
    "asset_limits": "No asset limits or tests apply[3][7]",
    "other_requirements": ["Washington state resident", "Primarily serves Medicare beneficiaries (enrolled in Medicare Parts A and/or B), but assists with related health insurance issues; no citizenship requirement specified for counseling services[3][4]"]
  },
  "benefits": {
    "type": "service|advocacy",
    "value": "Free, one-on-one counseling, education, and assistance on Medicare (Parts A, B, C, D), Medigap supplements, prescription drug plans, Medicare Savings Programs, Extra Help/Low-Income Subsidy, appeals, billing issues, fraud prevention, and coordination with other insurance; group outreach, presentations, and enrollment events; no dollar amounts, hours, or fixed limits specified[3][4][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-562-6900 (Statewide Health Insurance Benefits Advisors - SHIBA)", "TTY: 1-360-586-0241", "Website: https://www.insurance.wa.gov (Washington state Office of the Insurance Commissioner SHIBA page, inferred from context)", "In-person or local events through partnerships with area agencies on aging and community organizations (locations vary by region)"],
    "processing_time": "Immediate phone counseling available; no formal application processing as services are provided directly upon contact[3][4]",
    "waitlist": null,
    "forms": ["No specific forms required; assistance provided via phone or in-person without prior application[3][4]"],
    "documents": ["Medicare card, current insurance details, prescription drug list, income documents if applying for savings programs like Extra Help during counseling (optional, prepared in advance for efficiency)[3][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Washington state residents needing Medicare/health insurance counseling",
    "regional_variations": "Delivered statewide by Statewide Health Insurance Benefits Advisors (SHIBA) through the Office of the Insurance Commissioner, in partnership with local area agencies on aging and community organizations; local providers may handle in-person services, but core services uniform[3][4]",
    "offices_or_providers": ["Statewide coordination via SHIBA; contact 1-800-562-6900 for local counselors or events"]
  },
  "official_source": "https://www.insurance.wa.gov/about-us/office-insurance-commissioner-shiba (primary Washington SHIBA page, based on program context[4])",
  "gotchas": ["Not an insurance plan or financial aid program—provides counseling only, does not pay premiums or provide healthcare; free and unbiased (no sales commissions), unlike agents; often confused with WSHIP (high-risk pool) or Apple Health (Medicaid); best for education/appeals, not personalized plan sales[1][3][7]", "Services rely on trained volunteers/staff, so availability may depend on call volume or local events[3][6]"],
  "data_shape_notes": "no income/asset test; counseling-only service, not benefits/entitlements; volunteer/staff delivered via statewide hotline and local partners; part of national SHIP network focused on Medicare navigation[3][4][7]"
}

{
  "name": "Home Delivered Meals (via Aging & Disability Resources)",
  "eligibility": {
    "age": 60,
    "income_limits": "Below 185% of the Federal Poverty Level (FPL) for most Area Agency on Aging programs; exact dollar amounts vary annually and by household size (e.g., for 2025, 185% FPL is approximately $28,140 for 1 person, $38,036 for 2; check current HHS guidelines). Some programs like Sound Generations have no strict income test but suggested donations. Medicaid/Medicare Advantage or post-discharge may have separate rules without income limits.",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Washington State resident", "Homebound or limited mobility/unable to shop/cook for self", "55+ if American Indian/Alaska Native in some programs", "Referral from case manager for Medicaid/Mom's Meals", "King County residency for Sound Generations"]
  },
  "benefits": {
    "type": "service",
    "value": "Nutritionally balanced meals (hot, pre-packaged, or box meals) delivered to home; frequency varies: daily, weekly, semi-weekly, or twice monthly. Examples: 1 meal per day (Sound Generations), 2 meals/day for 14 days post-discharge (CHPW MA). Suggested donation $6.50/meal (Sound Generations) or free via Medicaid/referral.",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["Phone: Regional providers e.g., 360-533-5100 (O3A/Coastal Community Action)", "Online: Sound Generations application (specific URL not listed; submit online or mail)", "Contact case manager/health plan for Medicaid/Mom's Meals", "In-person/mail via local Area Agency on Aging"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Possible regional waitlists due to funding/provider capacity; not explicitly detailed.",
    "forms": ["Provider intake form for contractors (Snohomish); participant application for Sound Generations (online/print)"],
    "documents": ["Proof of age/residency", "Income verification for income-based programs", "Background checks for providers/volunteers", "Liability insurance for providers", "Referral info for Medicaid (ID, address, meal quantity, case manager details)"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Administered via regional Area Agencies on Aging (e.g., O3A for Clallam/Grays Harbor/Jefferson/Pacific Counties; Sound Generations for King County; Snohomish County providers)",
    "regional_variations": "Different providers, eligibility nuances (e.g., age 60+ statewide but 55+ for Native in O3A), delivery frequency, donation vs. free; funded by Older Americans Act via local AAA.",
    "offices_or_providers": ["O3A/Coastal Community Action (Clallam, Grays Harbor, Jefferson, Pacific)", "Sound Generations (King County)", "Mom's Meals (via Medicaid/health plan referral)", "Snohomish County providers"]
  },
  "official_source": "https://www.o3a.org/programs/nutrition-transportation/senior-nutrition-programs/",
  "gotchas": ["Not fully statewide—must contact local Area Agency on Aging; often requires homebound status, not just age/income; Medicaid/free meals need case manager referral; suggested donations common even if 'free'; post-discharge benefits temporary (e.g., 14 days); providers handle background checks/insurance, delaying access."],
  "data_shape_notes": "Administered regionally via Area Agencies on Aging with Older Americans Act funding; eligibility combines age, income (<185% FPL), homebound status; varies by county/provider; no uniform statewide application or asset test."
}

{
  "name": "Family Caregiver Support Program",
  "eligibility": {
    "age": null,
    "income_limits": "No specific income limits for a dedicated 'Family Caregiver Support Program' in Washington state; related programs like Medicaid Personal Care (MPC) have limits: $994/month for single applicant, $1,491/month for married couples (2026 figures, equivalent to 100% Federal Benefit Rate). MPC targets seniors 65+.[2][3]",
    "asset_limits": "MPC: $2,000 countable assets for singles (slightly higher for couples). Home exempt if applicant lives there, intends to return, spouse/disabled child/minor child lives there.[2][3]",
    "other_requirements": [
      "For MPC (primary avenue for paid family caregiving): Care recipient 65+ or Medicaid LTSS eligible, needs assistance with ADLs (extensive help with 1 ADL or minimal/supervision with 3+ ADLs via CARE assessment; no NFLOC required).[2][3]",
      "Caregiver: 18+, background check, not spouse (but other relatives like adult child, parent, sibling, extended family eligible). Must join Consumer Direct Care Network Washington (CDWA) as Individual Provider.[3][4]",
      "VA Program of Comprehensive Assistance for Family Caregivers (if Veteran): Caregiver 18+, family relation or lives full-time with Veteran; Veteran: 70%+ VA disability, honorable discharge, needs 6+ months in-person care, enrolled in VA health care.[1]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Paid caregiving via Medicaid Personal Care (MPC) or Community First Choice: Hours based on CARE assessment for ADLs (personal hygiene, dressing, toileting, transferring, mobility); family caregivers paid as Individual Providers through CDWA (rates not specified in sources). Training: 5 hours orientation/safety + 30 hours basic. VA: Stipends, respite, mental health, travel, health insurance.[1][2][3][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "For MPC/paid family care: Apply for Apple Health (Medicaid) LTSS via Washington Connection portal or local DSHS Home & Community Services office; then caregiver applies to CDWA portal.[4]",
      "VA: Online at va.gov, phone 1-855-260-3274, or mail VA Form 10-10CG to 10-10CG Evidence Intake Center, PO Box 5154, Janesville, WI 53547-5154.[1]"
    ],
    "processing_time": "Not specified; VA and Medicaid processes vary (MPC via case manager after Medicaid approval).[1][3]",
    "waitlist": "Not mentioned in sources; may depend on regional DSHS offices.[4]",
    "forms": ["VA Form 10-10CG (VA program); no specific form named for state MPC, uses Washington Connection portal.[1][4]"],
    "documents": ["Medicaid LTSS: Income/asset proof, functional needs via CARE assessment; background check for caregiver; VA: Disability rating proof, discharge papers.[1][2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered statewide via DSHS and CDWA, but contact local Home & Community Services offices.[4]",
    "regional_variations": "Varies by local DSHS office for assessments/wait times; CDWA statewide employer.[3][4]",
    "offices_or_providers": ["Local DSHS Home & Community Services offices; Consumer Direct Care Network Washington (CDWA).[4]"]
  },
  "official_source": "https://www.dshs.wa.gov (DSHS Apple Health LTSS; no single page for exact 'Family Caregiver Support Program'; closest is MPC via Washington Connection: https://www.washingtonconnection.org)",
  "gotchas": [
    "Not a standalone program; routes through Medicaid MPC/LTSS or VA (Veterans only). Spouses ineligible as paid caregivers in MPC.[3][4]",
    "Must qualify for Medicaid LTSS first; no NFLOC needed for MPC but ADL help required via CARE tool.[2]",
    "Background check mandatory; training required (35+ hours).[4]",
    "MPC doesn't cover room/board in assisted living.[3]"
  ],
  "data_shape_notes": "Tied to Medicaid LTSS/MPC (income/asset tested, ADL-based); statewide via CDWA for paid family caregivers (excludes spouses); separate VA track for Veterans; no fixed hours/dollars, assessment-driven."
}

{
  "name": "Legal Aid for Seniors (via Protection & Advocacy)",
  "eligibility": {
    "age": 60,
