    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Low-income status", "Washington resident", "Focus on issues like abuse, neglect, housing, benefits denial, healthcare, utilities[2][3]", "Tribal Elders may qualify at age 55+[3]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Counseling, advocacy, and/or representation in financial assistance, health care, housing, protective services; legal assistance for housing, benefits denial, healthcare, abuse/neglect, utilities; no specific dollar amounts or hours stated[2][3].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: CLEAR (for low-income seniors) 1-888-387-7111 (call 9:15am-12:15pm)[2][3]", "Phone: NJP general 1-888-201-1012[3]", "Phone: Eviction hotline 1-855-657-8387[3]", "Phone: Foreclosure hotline 1-800-606-4819[3]", "Phone: Sound Generations Senior Rights Assistance 206-448-5720 or 1-888-435-3377 (for estate planning, POA, etc.)[5]"],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": [],
    "documents": ["Not detailed; prepare info on income, specific legal issue (e.g., eviction, benefits denial)[2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Statewide via Northwest Justice Project (NJP) and partners like CLEAR; examples in Snohomish [2], King County (Sound Generations, Eastside Legal Assistance)[5][6], Olympic Area Agency on Aging (O3A)[3].",
    "regional_variations": "Services delivered through regional providers/contractors like NJP, Sound Generations (Seattle/Kent), Eastside Legal Assistance (King County); clinic-based in some areas (e.g., Elder Law Clinic appointments); O3A SLAC clinics ended June 30, 2025[3][5][6].",
    "offices_or_providers": ["Northwest Justice Project (NJP)[2][3][8]", "CLEAR (NJP program)[2][3]", "Sound Generations (Senior Rights Assistance, Seattle/Kent)[5]", "Eastside Legal Assistance Program (King County)[6]", "O3A (contracts with NJP, Olympic region)[3]"]
  },
  "official_source": "https://nwjustice.org (Northwest Justice Project, primary provider)[8]",
  "gotchas": ["Not a single centralized program; delivered via NJP/CLEAR and regional partners—call specific hotline for issue[2][3]", "O3A Senior Legal Advice Clinics (SLAC) ended June 30, 2025; shifted to NJP[3]", "Priority for low-income, those facing eviction/foreclosure/abuse; not general estate planning (use WA Law Help or State Bar)[3][5]", "Tribal Elders qualify at 55+, others 60+[3]", "Free services but may involve intake screening for eligibility[2]"],
  "data_shape_notes": "Decentralized statewide via NJP/CLEAR with regional contractors; no strict income/asset tables published; priority-based on need (eviction, abuse); age 60+ (55+ Tribal); clinic services ended in some regions post-2025[2][3]"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all regardless of financial status.",
    "asset_limits": "No asset limits or tests; no assets count or are exempt as there is no financial eligibility.",
    "other_requirements": ["Resident must live in a licensed long-term care facility in Washington (nursing homes, assisted living facilities, adult family homes, or veterans’ homes).", "Services also available to relatives, friends, administrators, employees, or any concerned individuals/groups about facility residents' welfare."][1][4][7]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including receiving and resolving complaints on quality of care, use of restraints, transfer/discharges, abuse, discrimination, financial exploitation, resident dignity, and rights; provision of information on resident rights and resources; confidential representation on behalf of residents; systemic advocacy for long-term care improvements.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact regional ombudsman via state hub (specific numbers on waombudsman.org); Website: https://www.waombudsman.org (submit complaint or inquiry form); In-person: Visit local long-term care facilities or regional offices (locations via waombudsman.org); Mail: Regional offices (addresses on county sites like Pierce, Snohomish). No formal application form required—contact to report issue or request help."],
    "processing_time": "Immediate response to complaints where possible; no fixed processing time stated, handled as case arises.",
    "waitlist": null,
    "forms": ["No specific form name/number; use online complaint submission on waombudsman.org or direct contact."],
    "documents": ["No documents required; provide details of complaint, resident info, and facility name. Confidentiality protected."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents in licensed long-term care facilities statewide.",
    "regional_variations": "Program operates through state office with regional volunteer networks and county programs (e.g., Pierce County, Snohomish County, Kitsap County, Multi-Service Center); volunteers assigned to specific facilities; contact varies by region but authority uniform under state law.",
    "offices_or_providers": ["State office: waombudsman.org; Regional examples: Pierce County (piercecountywa.gov/1302), Snohomish (snohomishcountywa.gov), Kitsap (kitsap.gov/hs), Multi-Service Center (mschelps.org)."]
  },
  "official_source": "https://www.waombudsman.org",
  "gotchas": ["Not a service provider or financial aid program—purely advocacy and complaint resolution, no direct care or funding.", "Not for non-licensed settings (e.g., private homes).", "Confidentiality is resident-directed; ombudsman acts only on resident's behalf unless authorized.", "Volunteers must avoid conflicts of interest (e.g., no recent employment at facilities).", "Families may overlook it due to low visibility despite existing since 1978."],
  "data_shape_notes": "no income test; advocacy-only for licensed LTC facility residents; relies on statewide volunteer network with regional delivery; open to anyone concerned about residents"
}

{
  "name": "Washington Charity Care",
  "eligibility": {
    "age": null,
    "income_limits": "Statewide minimum: Free care (100% discount) for income ≤300% of Federal Poverty Level (FPL), adjusted for family/household size; 75-80% discount for 301-350% FPL (varies slightly by hospital). Some hospitals extend up to 400% FPL. Exact FPL dollar amounts vary annually and by household size (e.g., consult current HHS FPL guidelines; hospitals provide charts). No statewide dollar table in law—hospitals must screen presumptively at 200% FPL and fully assess up to their policy limits.[1][3][5]",
    "asset_limits": "For 301-350% FPL tier only (Group 1 hospitals): Assets may reduce discount if 'unreasonable' burden; counts: equity in primary residence, retirement plans (except 401(k)), prepaid burial contracts/plots. Exempt: one motor vehicle (plus second if needed for work/medical), life insurance ≤$10,000 face value. ≤300% FPL: No asset test.[1][3]",
    "other_requirements": ["Medically necessary hospital services (inpatient, ER; may exclude non-hospital staff like independent radiologists/anesthesiologists)", "No citizenship requirement", "Must apply to hospital where care received", "Not required to apply for other programs if obviously/categorically ineligible or denied in prior 12 months"]
  },
  "benefits": {
    "type": "financial",
    "value": "100% discount on patient-responsible portion of hospital charges for ≤300% FPL; 75-80% discount for 301-350% FPL (hospital-specific); covers deductibles/co-pays even if insured; limited to medically necessary acute/psychiatric hospital services.[1][3][5]",
    "varies_by": "income_tier"
  },
  "application": {
    "methods": ["Contact specific hospital's financial assistance/charity care office (no central statewide phone/website)", "In-person: During hospital admission/discharge", "Phone/mail/online: Varies by hospital (e.g., Overlake: application process via financial services; Kaiser: 1-888-901-4636)", "No deadline to apply—retroactive possible"],
    "processing_time": "Initial determination on verbal/written app; full review after docs (e.g., 60 days for additional docs at some hospitals); high medical cost patients re-evaluated monthly, valid retro to 12 months.[2][3]",
    "waitlist": null,
    "forms": ["Hospital-specific 'Application for Financial Assistance' or 'Charity Care Application' (request from hospital billing/financial coordinator); statewide hospital policy list available via WA DOH or Washington Law Help"],
    "documents": ["W-2s, 3 recent pay stubs, most recent tax return, Medicaid/DSHS denial/approval, proof of other insurance/third-party coverage"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available at all WA-licensed acute care (RCW 70.41) and psychiatric hospitals (RCW 71.12); apply per hospital",
    "regional_variations": "Each hospital sets policy compliant with state law (e.g., Overlake: 80% discount 301-350% FPL effective 2025; some extend to 400% FPL); processing/docs may vary; no central wait times but hospital-dependent.[1][2][3][5]",
    "offices_or_providers": ["Hospital-specific financial assistance coordinators (e.g., Overlake Medical Center, Kaiser Permanente WA facilities)"]
  },
  "official_source": "https://www.washingtonlawhelp.org/en/guide-charity-care (consumer guide); hospital policies via WA DOH hospital list or direct hospital contact",
  "gotchas": ["Program is hospital-specific—not statewide single app; excludes non-hospital-employed providers (e.g., ER radiologists); must request app (hospitals notify but families should ask); assets only tested above 300% FPL; insured patients still qualify for deductibles/co-pays; no coverage for outpatient clinics or non-medically necessary care.[1][3][5]"],
  "data_shape_notes": "Hospital-by-hospital policies with state-mandated floors (300%/350% FPL tiers); no central app/form—must contact care hospital; income-based tiers, asset test only on partial-discount tier; presumptive eligibility at 200% FPL"
}
